import{_ as o,C as n,o as l,c as s,E as i,w as t,a as r,a0 as u}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to Belgium","description":"Immigration pathways and relocation guide for Belgium","frontmatter":{"layout":"doc","title":"Moving to Belgium","description":"Immigration pathways and relocation guide for Belgium"},"headers":[],"relativePath":"europe/belgium/moving-there.md","filePath":"europe/belgium/moving-there.md","lastUpdated":null}'),h={name:"europe/belgium/moving-there.md"};function m(d,e,c,g,f,p){const a=n("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:t(()=>[...e[0]||(e[0]=[r("EU/EEA: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Non-EU: Work Visa",-1)])]),_:1}),e[2]||(e[2]=u('<h1 id="moving-to-belgium" tabindex="-1">Moving to Belgium <a class="header-anchor" href="#moving-to-belgium" aria-label="Permalink to &quot;Moving to Belgium&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><p>Free movement applies. Register at your local commune (gemeente/commune) within 3 months of arrival. You need a valid ID/passport and proof of employment, study, or sufficient resources.</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">​</a></h3><p>Post-Brexit, UK citizens face similar requirements to third-country nationals unless they resided in Belgium before 31 December 2020 (protected under the Withdrawal Agreement). A single permit (work + residence) is required.</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Single Permit (Work Visa)</strong>: Requires a job offer from a Belgian employer. The employer must obtain a labour market test.</li><li><strong>Highly Skilled Migrant (EU Blue Card)</strong>: For roles requiring higher education with a salary threshold (~€60,000/year gross in 2025).</li><li><strong>Student Visa</strong>: For enrolment at a Belgian university. Part-time work permitted (20 hours/week).</li><li><strong>Family Reunification</strong>: If you have a spouse, registered partner, or family member in Belgium.</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Belgium does not have a specific digital nomad visa. Remote workers typically use the Single Permit route if employed by a Belgian company, or the freelance/independent status (indépendant/zelfstandige) if self-employed. Proof of sufficient income and health insurance is required.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] Obtain necessary visa (non-EU)</li><li>[ ] Arrange health insurance (private or register with mutuelle)</li><li>[ ] Research housing in Brussels, Antwerp, Ghent, or Liège</li><li>[ ] Gather medical records and HRT documentation (translated to Dutch/French)</li><li>[ ] Notify your bank and redirect mail</li><li>[ ] Learn basic Dutch or French (Flemish vs Walloon region)</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register at the local commune (within 8 days for non-EU, 3 months for EU)</li><li>[ ] Apply for residence card (non-EU)</li><li>[ ] Register with a mutuelle (health insurance fund)</li><li>[ ] Find a GP (huisarts/médecin généraliste)</li><li>[ ] Open a Belgian bank account</li><li>[ ] Apply for a Belgian SIM card</li><li>[ ] Register with Transgender Infopunt for local resources</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li>Monthly rent (1-bed): €700-1,200 (Brussels), €500-800 (other cities)</li><li>Monthly budget (single person): €1,200-1,800 excluding rent</li><li>Public transport: €50-80/month (subscription)</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><p>Temperate maritime — mild summers (18-23°C), cool winters (0-7°C), frequent rain year-round.</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Belgium has three official languages: Dutch (Flanders, north), French (Wallonia, south), and German (small eastern region). Brussels is bilingual (French/Dutch). English is widely spoken in Brussels and expat communities but less so in rural areas.</p>',22))])}const y=o(h,[["render",m]]);export{v as __pageData,y as default};
